before_code:
module sync_counter_16bit (
  input clk,
  input reset_n,
  input enable,
  input [15:0] load_value,
  input load_en
 );
  reg [15:0] counter;

  always @(posedge clk) begin
    if (~reset_n)
      counter <= 16'h0000;
    else if (load_en)
      counter <= load_value;
    else if (enable)
      counter <= counter + 1;
  end

endmodule

after_code:
module sync_counter_16bit (
  input clk,
  input reset_n,
  input enable,
  input [15:0] load_value,
  input load_en
 );
  reg [15:0] counter;

  always @(posedge clk or negedge reset_n) begin
    if (~reset_n)
      counter <= 16'h0000;
    else if (load_en)
      counter <= load_value;
    else if (enable)
      counter <= counter + 1;
  end

endmodule
